class Solution:
    def constructArray(self, n: int, k: int) -> List[int]:
        ans=[]; l,r=1,n
        while l<=r:
            if k>0:
                if k%2: ans.append(l); l+=1
                else: ans.append(r); r-=1
                k-=1
            else:
                ans.append(l); l+=1
        return ans

